var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"메이슨 씨, 메이슨 씨......","JPN":"はあ、メイソンさん……？","ENG":"Mr. Mason, Mr. Mason...","TWN":"梅森，梅森先生……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이것 참......쉽게 쉽게 가자니까 자꾸 일을 어렵게 만드시네.","JPN":"やれやれ……どうして簡単に終わることをこじらせてしまうんだか。","ENG":"I really wanted to keep things simple... and you just had to make everything complicated.","TWN":"這可真是……本來想簡單了事的，怎麼老是把事情搞得這麼複雜。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"정말이지, 덕분에 옷이 더러워졌잖아요.","JPN":"まったく、おかげで服が汚れたじゃないですか。","ENG":"You got my clothes dirty, for gosh sake.","TWN":"真是的，拜你所賜，我的衣服都弄髒了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이 옷 얼만지 아세요? 제가 이거 구한다고 얼마나 고생을......","JPN":"この服がいくらすると思います？\\nこれを手に入れようとかなり苦労したのに……","ENG":"Do you have any idea how much this cost me? I had to go through hell to get this...","TWN":"你知道這件衣服要多少錢嗎？我為了買它費了多少力氣……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"말하는 도중에 사람 머리에 총을 쏘다니. 버릇이 참 나쁘시네.","JPN":"人が話しているのに頭を撃つなんて。悪い癖ですよ。","ENG":"How could you shoot someone while they’re still talking? That’s rude.","TWN":"竟然會在說話的時候，對著別人的腦袋開槍？這可真是個壞習慣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"탄약 더 없어?","JPN":"弾薬、もっとないか？","ENG":"Got any more ammo?","TWN":"還有彈藥嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L16_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"간당간당해!","JPN":"ギリギリだ！","ENG":"We're running out!","TWN":"沒多少了！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"몰려온 침식체들도 거의 전멸이야!","JPN":"押し寄せてきた侵食体もほぼ全滅だ！","ENG":"Most of the C.O.'s have been wiped out too!","TWN":"湧過來的侵蝕體也幾乎全滅了！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"저 자식은 무슨 탱크 같은 건가...... 그걸 다 몰살시키다니 말이 돼, 이게?","JPN":"あいつは戦車か何かか……？\\nあれを全滅させるなんてあり得ないだろ？","ENG":"Is he some kind of a tank? How the hell did he kill all of them by himself?","TWN":"那傢伙是坦克嗎……竟然把那些侵蝕體都消滅了，這還像話嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"아까도 그렇고 지금도 그렇고......","JPN":"さっきもそうだし、今もそうだし……","ENG":"I can’t believe you managed to do that again...","TWN":"剛才也是，現在也是……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"도대체 침식체들은 어떻게 모아온 겁니까? 귀찮게시리.","JPN":"侵食体はどうやって集めてきたんです？\\nよくもまあ面倒をかけてくれましたね。","ENG":"How did you lure all those C.O.'s here? That was rather annoying.","TWN":"你們到底是怎麼把侵蝕體弄來的？真是麻煩。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이래서 내가 용병 나부랭이들을 좋아할 수가 없다니까.","JPN":"これだから傭兵は好きになれないんですよ。","ENG":"This is why I can never get myself to like these mercenary losers.","TWN":"這就是我不喜歡傭兵的理由。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"응? 그런데 그 여자 분은 안 보이는군요.","JPN":"おや？　ところで、あの女性の方が見当たりませんね。","ENG":"Huh? I don’t see the lady with you.","TWN":"嗯？話說，我好像沒看見那位女士呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"같이 있는 거 아니었나요?","JPN":"一緒にいませんでしたか？","ENG":"She's not with you?","TWN":"她沒和你們沒在一起嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"여자? 누구, 제인?","JPN":"女？　ジェーンのことか？","ENG":"What lady? Jane?","TWN":"女士？誰？你說珍妮？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"......뭐, 지금은 그런 이름이었던 것 같기도 하네요.","JPN":"……ええまあ、たしか今はそんな名前だった気がしますね。","ENG":"I guess that's her name. Yes.","TWN":"……這，好像就是那個名字吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아까 통로에서 널 막고 있었는데......?","JPN":"さっき通路であんたが入るのを塞いでいたんじゃ……？","ENG":"Wasn’t she holding you off in the corridor?","TWN":"她剛才還在通道阻攔你啊……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"지금 네가 들고 있는 게 걔가 가지고 있던 무전기라고.","JPN":"今あんたが持っている無線機は、あの女が持っていたものなんだよ。","ENG":"You answered my call on the radio she was holding.","TWN":"你現在拿著的就是她帶著的對講機。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"무슨......?","JPN":"どういうことですか……？","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"내가 도착했을 땐 이건 바닥에 굴러다니고 있었는데요?","JPN":"これは私が到着した時、すでに床に転がっていましたよ？","ENG":"But the radio was on the ground by the time I got there.","TWN":"我到的時候，這東西就已經在地上滾來滾去了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐? 그럴 리가......","JPN":"何？　そんなはずが……","ENG":"Huh? It can’t be...","TWN":"什麼？怎麼可能……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"......하. 이런 제기랄. 완전히 당했군.","JPN":"……は。まいったな。完全にやられた。","ENG":"Ha... Well, I’ll be damned. She totally got us both.","TWN":"……哈，天殺的，完全上當了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"설마...... 아니겠지?","JPN":"まさか……違うよな？","ENG":"What? It can’t be...","TWN":"不會吧……不是這樣吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"맞는 것 같은데요?","JPN":"お察しのとおりだと思いますが？","ENG":"Oh, I think it is.","TWN":"好像是呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 여자가, 젠장! 날 미끼로 썼다고?!","JPN":"あの女が、ちくしょう！　俺を囮にしたのか！？","ENG":"Damn that woman! She used me as bait?!","TWN":"那個女人，該死，把我當成誘餌了？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"또?!","JPN":"また！？","ENG":"Again?!","TWN":"又來了？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"날 이쪽으로 향하게 만들어 놓고 자기 볼일을 보러 간 모양이네요.","JPN":"私をこっちに向かわせて、自分の用を済ませに行ったみたいですね。","ENG":"Looks like she lured me here and went on about her own business.","TWN":"把我引到這裡後，她就去做自己的事情了呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"하긴, 그녀에 대해서 안다면 그 정도는 예상했어야 하는데......","JPN":"まあ、彼女を知っている者として、そのくらいは予想すべきでしたが……","ENG":"I suppose I should’ve seen this coming, knowing what she’s capable of...","TWN":"以我對她的了解，應該要想到會有這種事的……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이건 내 실수로군요.","JPN":"これは私のミスです。","ENG":"This is all on me.","TWN":"這是我的失誤呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......당신, 그녀가 뭐 하는 여잔지 알고 있는 건가?","JPN":"……あんた、彼女の正体を知っているのか？","ENG":"Hey... You know what she does for a living?","TWN":"……你知道那女人之前是幹什麼的嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"당연히 알죠. 왜 그런 질문을...... 음?","JPN":"もちろん知ってます。どうしてそんな質問を……ん？","ENG":"Of course I do. Why would you ask me that... unless?","TWN":"當然知道了，你為什麼會問這種問題……嗯？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"설마 메이슨 씨, 당신 그녀가 누군지도 모르고 여기까지 따라온 겁니까?","JPN":"まさかメイソンさん、彼女が誰かも知らないでここまでついて来たんですか？","ENG":"You didn’t follow her all the way here without knowing who she is, did you?","TWN":"梅森先生妳該不會連她是誰都不知道，就跟到這裡來了吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"하하하하! 이것 참 걸작이네요.","JPN":"はははは！　これは面白いですね。","ENG":"Hahahaha! Wow, this is pure gold.","TWN":"哈哈哈哈！這是傑作啊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"다른 사람도 아니고 존 메이슨, 당신이 그녀의 정체를 모른다니......","JPN":"他でもなくジョン・メイソン、あなたが彼女の正体を知らないとは……","ENG":"Of all the people, you don’t know who she is John Mason?","TWN":"不是別人，而是約翰·梅森竟然不知道她的身份……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"제기랄! 말 돌리지 말고 대답하라고!","JPN":"おい！　話を逸らさないで答えろ！","ENG":"Damn it! Stop skirting around answer me!","TWN":"該死！別轉移話題，回答我。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그건 본인에게 직접 물어보시죠.","JPN":"それは本人に直接聞いてください。","ENG":"Why don’t you ask her yourself?","TWN":"那個你就直接問本人吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"레이디의 뒷담화를 하는 건 제 취향이 아니니까.","JPN":"レディーの裏話をする趣味はありませんので。","ENG":"A gentleman never talks about a lady behind her back.","TWN":"背著女士說長道短的，可不是我的嗜好。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그럼 전 도둑고양이를 잡으러 가야겠군요.","JPN":"では、私は泥棒猫を捕まえに行きます。","ENG":"Well, then. Looks like I got a little thief to catch.","TWN":"那我要去抓那隻小野貓了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"아 참. 그전에 일을 아주 복잡하게 만들어 주신 메이슨 씨도 대가를 치러야겠죠?","JPN":"あ、そうだ。その前に事を複雑にしてくれた\\nメイソンさんにも対価を払ってもらわないとですね？","ENG":"Oh, by the way. Before I get to that, I ought to make you pay for complicating things for me.","TWN":"對了，在這之前，把事情弄得這麼複雜的梅森先生也得付出代價才行吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"젠장! 다들 응전을......!","JPN":"クソ！　みんな応戦を……！","ENG":"Damn it! Everyone, prepare to engage-","TWN":"該死！大家快迎戰……！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"<color=#ffd34c>존? 존, 듣고 있어?</color>","JPN":"<color=#ffd34c>ジョン？　ジョン、聞いてる？</color>","ENG":"<color=#ffd34c>John? John? Do you hear me?</color>","TWN":"<color=#ffd34c>約翰？約翰，你在聽嗎？？</color>"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};